import{c as r,Q as a,j as e,m as l}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"北京大学","description":"北京大学神经科学、心理与认知科学、前沿交叉学科博士项目指南 — 导师信息与申请流程","frontmatter":{"title":"北京大学","description":"北京大学神经科学、心理与认知科学、前沿交叉学科博士项目指南 — 导师信息与申请流程","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["neuroscience","bci","bme"],"tags":["北京大学","北京",985,"C9"],"admission-year":2027},"headers":[],"relativePath":"universities/peking.md","filePath":"universities/peking.md","lastUpdated":1780110618000}'),i={name:"universities/peking.md"};function n(o,t,s,d,h,u){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="北京大学" tabindex="-1">北京大学 <a class="header-anchor" href="#北京大学" aria-label="Permalink to &quot;北京大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日 | 🔴 <strong>2027年博士招生简章已发布</strong></p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>北京大学在神经科学领域拥有全国最强的学科实力，汇聚了<strong>方方</strong>（视觉认知）、<strong>李毓龙</strong>（GRAB神经递质探针）、<strong>吴思</strong>（计算神经科学）、<strong>饶毅</strong>（神经生物学）等国际知名学者。</p><h2 id="🆕-2027年博士招生-生命科学学院" tabindex="-1">🆕 2027年博士招生（生命科学学院） <a class="header-anchor" href="#🆕-2027年博士招生-生命科学学院" aria-label="Permalink to &quot;🆕 2027年博士招生（生命科学学院）&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">最新发布</p><p>北大生命科学学院已率先发布2027年&quot;申请-考核制&quot;博士招生简章！</p></div><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>招生简章</td><td><a href="https://admission.pku.edu.cn/zsxx/bszs/bssqkh/index.htm" target="_blank" rel="noreferrer">已发布</a></td></tr><tr><td>网上报名</td><td><strong>2026年10月20日 09:00 — 12月19日 17:00</strong></td></tr><tr><td>报名网址</td><td><a href="https://admission.pku.edu.cn/applications/" target="_blank" rel="noreferrer">admission.pku.edu.cn/applications/</a></td></tr><tr><td>材料截止</td><td><strong>2026年12月19日 17:00前寄达</strong>（仅接收EMS）</td></tr><tr><td>综合面试</td><td><strong>2027年1月初</strong></td></tr><tr><td>学制</td><td>5年（可申请4年毕业）</td></tr><tr><td>报名费</td><td>200元/志愿</td></tr><tr><td>英语要求</td><td>CET-4≥500 / CET-6≥470 / TOEFL≥90 / IELTS≥6.0</td></tr></tbody></table><p>⚠️ 以上为生命科学学院信息，其他学院（心理与认知科学学院等）可能有所不同。</p><p>北京大学在神经科学领域拥有国内最强的基础研究力量之一，依托心理学与认知科学学院、生命科学学院、前沿交叉学科研究院、IDG麦戈文脑科学研究所等平台，在系统神经科学、认知神经科学、计算神经科学方向具有深厚积累。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.pku.edu.cn" target="_blank" rel="noreferrer">https://www.pku.edu.cn</a></li><li>研究生招生网: <a href="https://admission.pku.edu.cn" target="_blank" rel="noreferrer">https://admission.pku.edu.cn</a></li><li>2026年博士招生简章: <a href="https://admission.pku.edu.cn" target="_blank" rel="noreferrer">北大研招网</a></li></ul><h2 id="相关学院" tabindex="-1">相关学院 <a class="header-anchor" href="#相关学院" aria-label="Permalink to &quot;相关学院&quot;">​</a></h2><h3 id="_1-心理与认知科学学院" tabindex="-1">1. 心理与认知科学学院 <a class="header-anchor" href="#_1-心理与认知科学学院" aria-label="Permalink to &quot;1. 心理与认知科学学院&quot;">​</a></h3><ul><li>学院官网: <a href="https://www.psy.pku.edu.cn" target="_blank" rel="noreferrer">https://www.psy.pku.edu.cn</a></li><li>核心方向: 认知神经科学、计算神经科学、感知觉与注意、学习与记忆</li><li>代表性导师: 方方（视觉认知神经科学）、吴思（计算神经科学）、纳家勇治（记忆神经科学）</li></ul><h3 id="_2-生命科学学院" tabindex="-1">2. 生命科学学院 <a class="header-anchor" href="#_2-生命科学学院" aria-label="Permalink to &quot;2. 生命科学学院&quot;">​</a></h3><ul><li>学院官网: <a href="https://www.bio.pku.edu.cn" target="_blank" rel="noreferrer">https://www.bio.pku.edu.cn</a></li><li>核心方向: 神经生物学、细胞生物学、分子神经科学</li><li>代表性导师: 李毓龙（神经递质探针）、饶毅（神经发育）</li></ul><h3 id="_3-前沿交叉学科研究院" tabindex="-1">3. 前沿交叉学科研究院 <a class="header-anchor" href="#_3-前沿交叉学科研究院" aria-label="Permalink to &quot;3. 前沿交叉学科研究院&quot;">​</a></h3><ul><li>官网: <a href="http://www.aais.pku.edu.cn" target="_blank" rel="noreferrer">http://www.aais.pku.edu.cn</a></li><li>核心方向: 纳米科学、数据科学、生物医学工程交叉</li></ul><h3 id="_4-idg麦戈文脑科学研究所" tabindex="-1">4. IDG麦戈文脑科学研究所 <a class="header-anchor" href="#_4-idg麦戈文脑科学研究所" aria-label="Permalink to &quot;4. IDG麦戈文脑科学研究所&quot;">​</a></h3><ul><li>官网: <a href="https://mgv.pku.edu.cn" target="_blank" rel="noreferrer">https://mgv.pku.edu.cn</a></li><li>北大神经科学的整合平台，涵盖分子到认知层面的脑科学研究</li></ul><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-神经科学-认知神经科学方向-——" tabindex="-1">—— 神经科学 / 认知神经科学方向 —— <a class="header-anchor" href="#——-神经科学-认知神经科学方向-——" aria-label="Permalink to &quot;—— 神经科学 / 认知神经科学方向 ——&quot;">​</a></h3><h4 id="方方-—-教授、博导" tabindex="-1">方方 — 教授、博导 <a class="header-anchor" href="#方方-—-教授、博导" aria-label="Permalink to &quot;方方 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 心理与认知科学学院</li><li><strong>身份</strong>: 北京大学麦戈文脑科学研究所 PI、国家杰出青年基金获得者</li><li><strong>个人主页</strong>: <a href="https://www.psy.pku.edu.cn" target="_blank" rel="noreferrer">北大心理学院师资</a></li></ul><p><strong>研究方向</strong>:</p><ul><li>视觉认知神经科学</li><li>视觉注意与意识</li><li>感知觉学习与可塑性</li><li>fMRI、EEG、心理物理学</li></ul><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h4 id="吴思-—-教授、博导" tabindex="-1">吴思 — 教授、博导 <a class="header-anchor" href="#吴思-—-教授、博导" aria-label="Permalink to &quot;吴思 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 心理与认知科学学院</li><li><strong>研究方向</strong>: 计算神经科学、神经信息编码、类脑计算</li><li><strong>2026年博士生招生</strong>: 待确认</li></ul><hr><h4 id="纳家勇治-—-研究员、博导" tabindex="-1">纳家勇治 — 研究员、博导 <a class="header-anchor" href="#纳家勇治-—-研究员、博导" aria-label="Permalink to &quot;纳家勇治 — 研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 心理与认知科学学院</li><li><strong>已发布</strong>: 2026年博士研究生招生（详见学院通知公告）</li><li><strong>研究方向</strong>: 记忆神经科学、认知神经科学</li><li><strong>招生公告</strong>: <a href="https://www.psy.lb.pku.edu.cn/xwzx/tzgg/df3bdbfd23154d92a70d451564a94c77.htm" target="_blank" rel="noreferrer">https://www.psy.lb.pku.edu.cn/xwzx/tzgg/df3bdbfd23154d92a70d451564a94c77.htm</a></li></ul><hr><h4 id="李毓龙-—-教授、博导" tabindex="-1">李毓龙 — 教授、博导 <a class="header-anchor" href="#李毓龙-—-教授、博导" aria-label="Permalink to &quot;李毓龙 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生命科学学院</li><li><strong>身份</strong>: 北大-清华生命科学联合中心 PI</li><li><strong>研究方向</strong>: <ul><li>神经递质探针开发（GRAB探针系列）</li><li>神经递质动态监测</li><li>分子神经科学</li></ul></li></ul><p><strong>学术成果</strong>: 开发了系列基因编码的神经递质荧光探针（GRAB探针），被全球数百家实验室使用。</p><p><strong>2026年博士生招生</strong>: 待确认</p><hr><h2 id="_2026年博士招生" tabindex="-1">2026年博士招生 <a class="header-anchor" href="#_2026年博士招生" aria-label="Permalink to &quot;2026年博士招生&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">待公布</p><p>北京大学2026年博士招生简章通常于<strong>2025年9月</strong>发布。以下为参考信息。</p></div><h3 id="申请时间-预估" tabindex="-1">申请时间（预估） <a class="header-anchor" href="#申请时间-预估" aria-label="Permalink to &quot;申请时间（预估）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>时间</th></tr></thead><tbody><tr><td>招生简章发布</td><td>2025年9月</td></tr><tr><td>网上报名</td><td>2025年10月</td></tr><tr><td>材料提交</td><td>2025年10月-12月</td></tr><tr><td>综合考核</td><td>2026年3月-4月</td></tr></tbody></table><h3 id="招生方式" tabindex="-1">招生方式 <a class="header-anchor" href="#招生方式" aria-label="Permalink to &quot;招生方式&quot;">​</a></h3><p><strong>申请-考核制</strong>。部分学科和专项计划可能有不同时间安排。</p><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>最适合的方向是计算神经科学/神经工程交叉</strong>：吴思教授的计算神经科学方向可能与你的BME神经技术背景有交叉</li><li><strong>李毓龙实验室值得关注</strong>：神经递质探针工具与你的脑类器官研究（钙成像）有技术上的衔接，GRAB探针也可用于脑类器官</li><li><strong>北大偏好学术型候选人</strong>：相比清华的工程导向，北大更偏重基础科学研究，研究计划需突出科学问题深度</li><li><strong>麦戈文研究所是核心平台</strong>：汇聚了校内多个学院的PI，适合跨方向申请</li><li><strong>竞争非常激烈</strong>：北大神经科学类博士名额有限，建议提前联系导师</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="https://admission.pku.edu.cn" target="_blank" rel="noreferrer">北大研招网</a>（访问日期: 2026-05-25）</li><li><a href="https://mgv.pku.edu.cn" target="_blank" rel="noreferrer">麦戈文脑科学研究所</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以北京大学研究生院官网最新公告为准。</em></p><p><em>下次更新建议: 2026年8月</em></p>',55)])])}const g=r(i,[["render",n]]);export{c as __pageData,g as default};
